    ('ingles','vocabulario',1,'Cores em Inglês',20,'{"questions":[{"type":"choice","prompt":"Como se diz AZUL em inglês?","options":["Red","Blue","Green","Yellow"],"answer":1,"explanation":"Blue = Azul. Red = Vermelho, Green = Verde, Yellow = Amarelo."},{"type":"choice","prompt":"What color is the sun?","options":["Blue","Green","Yellow","White"],"answer":2,"explanation":"The sun is Yellow! O sol é amarelo."},{"type":"choice","prompt":"Como se diz VERMELHO?","options":["Pink","Orange","Red","Purple"],"answer":2,"explanation":"Red = Vermelho."},{"type":"match","prompt":"Combine as cores:","pairs":[{"left":"Blue","right":"Azul"},{"left":"Red","right":"Vermelho"},{"left":"Green","right":"Verde"},{"left":"Yellow","right":"Amarelo"}],"explanation":"Cores básicas em inglês!"},{"type":"choice","prompt":"Como se diz VERDE?","options":["Blue","Red","Green","Yellow"],"answer":2,"explanation":"Green = Verde."}]}'),

