    ('matematica','basica',1,'Adição e Subtração',20,'{"questions":[{"type":"choice","prompt":"Quanto é 25 + 37?","options":["52","62","61","72"],"answer":1,"explanation":"25+37: 5+7=12, escreve 2 carrega 1; 2+3+1=6. Total: 62."},{"type":"choice","prompt":"100 - 43 = ?","options":["57","67","47","53"],"answer":0,"explanation":"100 - 43 = 57. Confirme: 43+57=100 ✓"},{"type":"choice","prompt":"150 produtos, vendeu 68. Quantos restaram?","options":["72","82","92","62"],"answer":1,"explanation":"150 - 68 = 82 produtos."},{"type":"choice","prompt":"999 + 1 = ?","options":["999","1000","1001","998"],"answer":1,"explanation":"999 + 1 = 1.000. Passamos de centena para milhar!"},{"type":"choice","prompt":"João tem 45 reais e ganhou 28. Total?","options":["63","73","83","53"],"answer":1,"explanation":"45 + 28 = 73 reais."}]}'),

    ('matematica','basica',1,'Multiplicação e Divisão',20,'{"questions":[{"type":"choice","prompt":"7 × 8 = ?","options":["54","56","58","64"],"answer":1,"explanation":"7×8 = 56. Dica: 7×8=7×4×2=28×2=56."},{"type":"choice","prompt":"72 ÷ 9 = ?","options":["6","7","8","9"],"answer":2,"explanation":"72÷9=8, pois 9×8=72."},{"type":"choice","prompt":"12 ovos × 5 caixas = ?","options":["50","55","60","65"],"answer":2,"explanation":"12×5=60 ovos."},{"type":"choice","prompt":"48 balas ÷ 6 crianças = ?","options":["6","7","8","9"],"answer":2,"explanation":"48÷6=8 balas cada."},{"type":"choice","prompt":"15 × 4 = ?","options":["45","55","60","65"],"answer":2,"explanation":"15×4=60. Dica: 10×4+5×4=40+20=60."}]}'),

