    ('matematica','algebra',2,'Equações 1° Grau',30,'{"questions":[{"type":"choice","prompt":"2x + 4 = 10. Qual o valor de x?","options":["2","3","4","5"],"answer":1,"explanation":"2x=10-4=6. x=6÷2=3."},{"type":"choice","prompt":"x - 7 = 13. x = ?","options":["6","13","20","26"],"answer":2,"explanation":"x=13+7=20."},{"type":"choice","prompt":"3x = 21. x = ?","options":["6","7","8","9"],"answer":1,"explanation":"x=21÷3=7."},{"type":"choice","prompt":"Daqui a 5 anos terá 30 anos. Qual a equação?","options":["x-5=30","x+5=30","5x=30","x×30=5"],"answer":1,"explanation":"Idade atual + 5 = 30. x+5=30, x=25."},{"type":"choice","prompt":"4x - 8 = 16. x = ?","options":["4","5","6","7"],"answer":2,"explanation":"4x=16+8=24. x=24÷4=6."}]}'),

    ('matematica','geometria',2,'Área e Perímetro',30,'{"questions":[{"type":"choice","prompt":"Área do retângulo: base 8m, altura 5m?","options":["13m²","26m²","40m²","80m²"],"answer":2,"explanation":"Área=base×altura=8×5=40m²."},{"type":"choice","prompt":"Perímetro do quadrado lado 6cm?","options":["12cm","18cm","24cm","36cm"],"answer":2,"explanation":"Perímetro=4×lado=4×6=24cm."},{"type":"choice","prompt":"Fórmula da área do triângulo?","options":["b×h","(b×h)÷2","b+h","2×(b+h)"],"answer":1,"explanation":"Área triângulo=(base×altura)÷2."},{"type":"choice","prompt":"Quarto 4m×3m. Área para piso?","options":["7m²","12m²","14m²","24m²"],"answer":1,"explanation":"Área=4×3=12m²."},{"type":"choice","prompt":"Triângulo base 10m altura 6m. Área?","options":["30m²","40m²","50m²","60m²"],"answer":0,"explanation":"Área=(10×6)÷2=60÷2=30m²."}]}'),

    ('matematica','algebra',3,'Equações 2° Grau',40,'{"questions":[{"type":"choice","prompt":"x² - 5x + 6 = 0. Quais são as raízes?","options":["x=1 e x=6","x=2 e x=3","x=-2 e x=-3","x=1 e x=-6"],"answer":1,"explanation":"Fatorando: (x-2)(x-3)=0 → x=2 ou x=3."},{"type":"choice","prompt":"Se Δ < 0, a equação tem:","options":["Duas raízes reais","Uma raiz real","Nenhuma raiz real","Infinitas raízes"],"answer":2,"explanation":"Δ<0 significa sem raízes reais."},{"type":"choice","prompt":"Qual o Δ para x² - 6x + 9 = 0?","options":["0","9","36","-9"],"answer":0,"explanation":"Δ=(-6)²-4×1×9=36-36=0. Raiz dupla!"},{"type":"choice","prompt":"2x² + 4x = 0. Uma raiz é x=0. Qual a outra?","options":["1","-1","2","-2"],"answer":3,"explanation":"2x(x+2)=0 → x=0 ou x=-2."},{"type":"choice","prompt":"Δ=25, a=1, b=-7. Raiz maior?","options":["4","5","6","7"],"answer":2,"explanation":"x=(-(-7)+√25)/(2×1)=(7+5)/2=12/2=6."}]}');

